function evaluator_optimizer(task, MAX_ITERS=4):
    candidate = generator.generate(task)

    for i in 1..MAX_ITERS:
        verdict = evaluator.score(
            task=task,
            candidate=candidate,
            criteria=CRITERIA,
        )
        # verdict = {pass: bool, score: float, feedback: "..."}

        if verdict.pass:
            return candidate, verdict

        # Feedback must be concrete improvement points, not a vague rating.
        candidate = generator.revise(
            task=task,
            previous=candidate,
            feedback=verdict.feedback,
        )

    return candidate, verdict              # budget hit — best-effort

RUBRIC = [
    "factual_error",
    "unsupported_claim",
    "tone_mismatch",
    "missing_citation",
]

# Schema enforces: every finding's 'category' MUST be one of RUBRIC.
FINDING_SCHEMA = {
    type: "object",
    properties: {
        findings: {
            type: "array",
            items: {
                type: "object",
                properties: {
                    category: {enum: RUBRIC},      # <-- frozen
                    span: {type: "string"},
                    fix: {type: "string"},
                },
                required: ["category", "span", "fix"],
            },
        },
    },
}

function review(artefact):
    response = llm.generate(
        prompt=render(RUBRIC, artefact),
        response_schema=FINDING_SCHEMA,
        temperature=0.0,
    )
    # Schema validation rejects any invented category at parse time.
    return validate(response, FINDING_SCHEMA)

function generate_with_prm(question, N=8):
    candidates = []
    for i in 1..N:
        # Each candidate is a sequence of steps, not a single answer.
        steps = llm.generate_cot(question, temperature=0.7, seed=i)
        step_scores = [prm.score(question, steps[:k+1]) for k in 0..len(steps)-1]
        candidates.append({
            steps: steps,
            step_scores: step_scores,
            min_step: min(step_scores),       # weakest link
            final: extract_final(steps),
        })

    # Reject any candidate with a low intermediate step, even if its
    # final answer looks fine — the reasoning is unreliable.
    viable = [c for c in candidates if c.min_step >= MIN_STEP_THRESHOLD]
    if not viable:
        return abstain("no viable trace")

    return max(viable, key=lambda c: mean(c.step_scores)).final

function reflect(task, MAX_ITERS=3):
    draft = llm.generate(task)

    for i in 1..MAX_ITERS:
        critique = llm.generate(
            prompt=critic_persona_prompt(task, draft),
            # critic_persona: 'You are a senior reviewer. List concrete issues.'
        )

        if critique.says_no_issues():
            return draft

        draft = llm.generate(
            prompt=revise_prompt(task, draft, critique),
        )

    return draft

function self_consistency(prompt, N=8, temperature=0.7):
    samples = []
    for i in 1..N:
        out = llm.generate(prompt, temperature=temperature, seed=i)
        samples.append(extract_answer(out))

    if answer_type == "discrete":
        answer, count = majority_vote(samples)
        confidence = count / N
    elif answer_type == "numeric":
        answer = median(samples)
        confidence = 1.0 - normalized_iqr(samples)
    else:
        answer = judge.pick_best(prompt, samples)
        confidence = judge.agreement_score(samples)

    log("self_consistency_variance", variance(samples))
    return {answer: answer, confidence: confidence, n: N}

function self_refine(task, MAX_ITERS=4):
    output = llm.generate(generate_prompt(task))

    for i in 1..MAX_ITERS:
        # SAME model, feedback role.
        feedback = llm.generate(feedback_prompt(task, output))

        if feedback.says_no_more_issues():
            return output

        # SAME model, refine role.
        output = llm.generate(refine_prompt(task, output, feedback))

    return output

import instructor
from pydantic import BaseModel, field_validator


class Email(BaseModel):
    subject: str
    body: str

    @field_validator("body")
    @classmethod
    def under_80_words(cls, v: str) -> str:
        if len(v.split()) > 80:
            raise ValueError("body must be 80 words or fewer; tighten it")
        return v


client = instructor.from_provider("openai/gpt-4o-mini")

# max_retries = up to N self-refine passes. On each ValidationError the
# same model is re-prompted with the validator's message — generate,
# feedback (validator), refine, all in the same provider.
email = client.create(
    response_model=Email,
    max_retries=4,
    messages=[
        {"role": "user", "content": "Draft a refund-approval email for order #42."}
    ],
)
print(email.subject, email.body)

# Register the world model as just another tool.
world_model_tool = Tool(
    name="simulate",
    description="Roll out a candidate action sequence from the current state.",
    schema={
        state: STATE_SCHEMA,
        actions: list_of(ACTION_SCHEMA),
        horizon: int,
    },
    invoke=lambda args: world_model.rollout(**args),  # returns frames + uncertainty
)

function plan_with_simulation(goal, candidate_action_sequences):
    rollouts = []
    for actions in candidate_action_sequences:
        rollout = world_model_tool.invoke({
            state: perceive_current(),
            actions: actions,
            horizon: H,
        })
        rollouts.append({
            actions: actions,
            predicted: rollout.frames,
            uncertainty: rollout.uncertainty,
        })

    # Agent compares text-level reasoning against simulator predictions.
    chosen = agent.pick(goal, rollouts)

    # Gate irreversible / expensive actions on simulator agreement.
    if chosen.actions.is_irreversible() and chosen.uncertainty > GATE:
        return abstain("world model uncertain on irreversible action")
    return chosen.actions
